CREATE   PROC [dbo].[TR_KEHOACH_HANGTRANG_CHITIET_GETALL]
(
	@congdoan nvarchar(50),
	@madonhang nvarchar(MAX),
	@tungay date,
	@denngay date
)
AS
BEGIN
	DECLARE @SUB_SQL NVARCHAR(MAX) = '';
	IF @tungay IS NOT NULL AND @denngay IS NOT NULL
	BEGIN
		SET @SUB_SQL = @SUB_SQL + CHAR(13) + CHAR(10) + N' AND B.ngaythang BETWEEN @tungay AND @denngay ';
	END

	IF @madonhang IS NOT NULL
	BEGIN
		SET @SUB_SQL = @SUB_SQL + CHAR(13) + CHAR(10) + N' AND A.madonhang IN (SELECT LTRIM(RTRIM([value])) FROM string_split(@madonhang, '',''))';
	END
	
	DECLARE @SQL NVARCHAR(MAX) = '';
	SET @SQL = N'
	SELECT A.id_kehoach, B.id_chitiet, A.congdoan, A.madonhang, 
		A.masp, C.tensp, C.hehang, 
		A.soluong_donhang, B.ngaythang, B.soluong_kehoach, B.xacnhan
	FROM tr_kehoach_hangtrang A
	INNER JOIN tr_kehoach_hangtrang_chitiet B ON A.id_kehoach = B.id_kehoach
	INNER JOIN tr_sanpham C ON A.masp = C.masp
	WHERE A.congdoan = @congdoan
	ORDER BY A.madonhang, B.ngaythang, A.masp'

	SET @SQL = @SQL + @SUB_SQL;
	EXEC sp_executesql @sql, N'@congdoan nvarchar(50), @madonhang nvarchar(MAX), @tungay date, @denngay date', @congdoan, @madonhang, @tungay, @denngay;
	--ORDER BY B.ngaythang, A.madonhang, A.masp
END
